export const EXAM_QUESTIONS = [
  { year: "2024-T1", nr: 1, points: 1, opgave: "Avatar", context: "In de film Avatar wordt Jake Sully draadloos verbonden met een gekweekt Na'vi-lichaam. Zijn menselijke lichaam ligt in een laboratorium en krijgt prikkels, terwijl ook zijn Na'vi-lichaam zintuiglijk wordt geprikkeld. Andy Clark beschrijft de experimenten 'pijn in het bureaublad' en 'de verlengde neus', waarin het lichaam grenzen kan inlijven.", question: "Leg met een van deze twee experimenten uit dat Jake volgens de opvatting van Clark kan leren omgaan met zijn Na'vi-lichaam.", model: "1p uitleg met experiment 'pijn in het bureaublad' of 'verlengde neus': zintuiglijke prikkeling van eigen lichaam en omgeving kan leiden tot het inlijven van het Na'vi-lichaam, zoals een bureaublad/andermans neus in het experiment ingelijfd kan worden bij het eigen lichaam.", philosophers: ["Clark"], kwestie: 3, vraagtype: "T" , lia: [{ deel: 2, hoofdstuk: 8, pagina: "2–6" }] },
  { year: "2024-T1", nr: 2, points: 2, opgave: "Avatar", context: "Jake beweegt aanvankelijk klungelig met zijn Na'vi-lichaam, maar leert zich later steeds beter te bewegen. Clarks begrippen 'interface' en 'cyborg' beschrijven verschillende verhoudingen tussen mens en techniek.", question: "Leg uit welk van deze twee begrippen past bij de verhouding die Jake in het begin tot zijn Na'vi-lichaam heeft. Leg vervolgens uit welk van deze twee begrippen past bij de verhouding die Jake later tot zijn Na'vi-lichaam heeft.", model: "1p uitleg dat Jakes beginverhouding past bij 'interface': Jake moet zich bewust tot dit lichaam richten om ermee om te gaan. 1p uitleg dat Jakes latere verhouding past bij 'cyborg': zijn Na'vi-lichaam verdwijnt naar de achtergrond van zijn handelen.", philosophers: ["Clark"], kwestie: 3, vraagtype: "T" , lia: [{ deel: 2, hoofdstuk: 8, pagina: "2–6" }] },
  { year: "2024-T1", nr: 3, points: 2, opgave: "Avatar", context: "Volgens Jos de Mul is de mens van nature kunstmatig, maar verandert de menselijke, humanistische identiteit door de omgang met techniek.", question: "Geef weer wat volgens De Mul het mensbeeld van het humanisme is. Leg vervolgens met een voorbeeld van hedendaagse techniek uit dat de humanistische identiteit van de mens volgens De Mul verandert door omgang met techniek.", model: "1p weergave humanistisch mensbeeld volgens De Mul: de mens is een redelijk wezen met zelfbewustzijn / een eigen wil / de vrijheid om zelf keuzes te maken. 1p uitleg met voorbeeld hedendaagse techniek dat humanistische identiteit verandert: deze techniek oefent invloed uit op het zelfbewustzijn/de eigen wil/de vrijheid om zelf keuzes te maken.", philosophers: ["De Mul"], kwestie: 3, vraagtype: "R+T" , lia: [{ deel: 2, hoofdstuk: 11, pagina: "19–23" }] },
  { year: "2024-T1", nr: 4, points: 2, opgave: "Avatar", context: "In het begin wordt Jake door de Na'vi 'skxawng' (idioot) genoemd; hij schaamt zich en wil bewijzen dat hij een goede Na'vi kan zijn. Frantz Fanon beschrijft hoe zijn bestaanservaring als zwarte man wordt gevormd door de objectiverende blik van anderen.", question: "Leg met het voorbeeld van Jake als 'skxawng' uit dat Jakes bestaanservaring als Na'vi mede wordt gevormd door de blik van anderen. Leg vervolgens uit dat Jakes bestaanservaring niet wordt overstemd door de blik van anderen, zoals bij Fanon.", model: "1p uitleg met 'skxawng' dat Jakes bestaanservaring mede wordt gevormd door blik van anderen: Jakes subjectieve ervaring van zichzelf verandert als hij zichzelf via blik van Na'vi als 'idioot' ziet. 1p uitleg dat Jakes bestaanservaring niet wordt overstemd zoals bij Fanon: Jake ondervindt een objectivering met beperktere aard/reikwijdte/duur dan Fanon, waardoor deze minder diep ingrijpt / Jakes opdracht om geaccepteerd te worden sluit aan bij zijn eigen wens.", philosophers: ["Fanon"], kwestie: 4, vraagtype: "T" , lia: [{ deel: 1, hoofdstuk: 4, pagina: "26–27" }] },
  { year: "2024-T1", nr: 5, points: 1, opgave: "Avatar", context: "In Avatar zijn alle levende wezens via een soort zenuwnetwerk verbonden. Jake mag zich met dit dradennetwerk verbinden via 'zenuwdraden' in zijn haar en ervaart dan de onderlinge verbondenheid van alles in de natuur en zijn plek daarin. Dit is voor Jake een bestaanservaring.", question: "Leg met deze bestaanservaring van Jake uit dat bestaanservaringen een ethische dimensie hebben.", model: "1p uitleg met Jakes bestaanservaring: onze ervaring dat wij op een bepaalde manier bestaan, zoals Jakes gevoel van verbondenheid met alles in de natuur, gaat gepaard met de opdracht om ons tot dat bestaan te verhouden.", philosophers: [], kwestie: 4, vraagtype: "T" , lia: [] },
  { year: "2024-T1", nr: 6, points: 2, opgave: "Avatar", context: "Het mycelium-netwerk verbindt wortels van planten en bomen en zorgt voor uitwisseling van informatie en voedsel; oudere bomen kunnen meer water aan eigen nakomelingen doorgeven. Volgens Timothy Morton hebben bomen net als mensen handelingsvermogen.", question: "Leg met het voorbeeld van het mycelium een van de redenen van Morton uit dat bomen handelingsvermogen hebben, net als mensen. Geef vervolgens met het begrippenpaar 'vrijheid en determinisme' een argument dat bomen, in tegenstelling tot mensen, geen handelingsvermogen hebben.", model: "1p uitleg met mycelium dat bomen volgens Morton handelingsvermogen hebben: de grens tussen bewust en onbewust handelen is niet goed te trekken / het vermogen van mensen om vooruit te denken wordt overschat. 1p argument met 'vrijheid en determinisme' dat bomen geen handelingsvermogen hebben: gedrag van bomen is niet vrij maar gedetermineerd.", philosophers: ["Morton"], kwestie: 1, vraagtype: "T+Arg" , lia: [{ deel: 2, hoofdstuk: 12, pagina: "24–27" }] },
  { year: "2024-T1", nr: 7, points: 1, opgave: "Avatar", context: "Het schimmelnetwerk doet sommigen denken aan een harmonieuze natuur waarin mensen verbonden zijn met allerlei niet-menselijke wezens. Volgens Morton is ecologisch denken belangrijk, maar leidt het niet tot een geruststellend besef van harmonie.", question: "Leg uit dat ecologisch denken over het mycelium volgens Morton niet zal leiden tot een geruststellend besef van harmonie met de natuur.", model: "1p uitleg: we missen een referentiepunt om onze verbondenheid met het mycelium betekenis te geven.", philosophers: ["Morton"], kwestie: 1, vraagtype: "T" , lia: [{ deel: 2, hoofdstuk: 12, pagina: "24–27" }] },
  { year: "2024-T1", nr: 8, points: 2, opgave: "Avatar", context: "Schimmels leveren antibiotica tegen infectieziektes, maar bacteriën kunnen resistent worden, met onbeheersbare uitbraken tot gevolg. Bruno Latour legt met de actor-netwerktheorie uit dat de grens tussen menselijk en niet-menselijk is vervaagd.", question: "Leg uit dat de grens tussen menselijk en niet-menselijk volgens Latour is vervaagd. Gebruik daarbij: de actor-netwerktheorie, en het voorbeeld van antibiotica.", model: "1p uitleg met actor-netwerktheorie: mensen zijn deel van een netwerk van actoren, waarin ook niet-levende actoren zaken in beweging kunnen zetten. 1p uitleg met voorbeeld antibiotica: antibiotica hebben als niet-levende actoren gevolgen voor de mens.", philosophers: ["Latour"], kwestie: 4, vraagtype: "T" , lia: [{ deel: 2, hoofdstuk: 13, pagina: "32–37" }] },
  { year: "2024-T1", nr: 9, points: 2, opgave: "Avatar", context: "In Avatar willen mensen het bos van de Na'vi vernietigen om grondstoffen te winnen. Jake sluit zich aan bij de Na'vi. Latour stelt voor om een Parlement van de dingen op te richten zodat het niet-menselijke gehoord kan worden.", question: "Leg met het voorbeeld van het bos van de Na'vi uit dat Latour een voorstander is van de oprichting van een Parlement van de dingen. Beargumenteer met een voorbeeld of jij denkt dat het goed is om een Parlement van de dingen op te richten.", model: "1p uitleg met bos van Na'vi: de niet-menselijke stem (het bos) kan zo worden gehoord, waardoor mensen hier verantwoordelijkheid voor kunnen nemen. 1p argumentatie met voorbeeld of het goed is om een Parlement van de dingen op te richten.", philosophers: ["Latour"], kwestie: 4, vraagtype: "T+Arg" , lia: [{ deel: 2, hoofdstuk: 13, pagina: "32–37" }] },
  { year: "2024-T1", nr: 10, points: 3, opgave: "Artonauten", context: "Tekst 1 (Ruben Jacobs): de luchtballon en fotografie maakten het mogelijk dat de mens de aarde vanuit de hemel kon aanschouwen; zonder aeronaut geen vliegtuig, geen helikopter, geen 'helikopterblik'. Jacobs stelt dat de luchtballon zorgt voor een nieuw begrip van ruimte. Lakoff & Johnson onderscheiden oriënterende en ontologische metaforen.", question: "Leg met een voorbeeld uit wat oriënterende metaforen zijn. Leg vervolgens met een voorbeeld uit wat ontologische metaforen zijn. Beargumenteer tot slot of jij het eens bent met de stelling van Jacobs. Gebruik daarbij de opvatting van Lakoff & Johnson over oriënterende metaforen.", model: "1p uitleg met voorbeeld dat oriënterende metaforen uitdrukken hoe ons lichaam op de wereld is georiënteerd. 1p uitleg met voorbeeld dat ontologische metaforen abstracte begrippen uitdrukken op basis van ervaring met fysieke objecten. 1p argument of Jacobs gelijk heeft, met Lakoff & Johnsons opvatting dat oriënterende metaforen geworteld zijn in onze lichamelijke ervaring.", philosophers: ["Jacobs", "Lakoff", "Johnson"], kwestie: 3, vraagtype: "T+Arg" , lia: [{ deel: 1, hoofdstuk: 5, pagina: "31–32" }] },
  { year: "2024-T1", nr: 11, points: 2, opgave: "Artonauten", context: "De helikopterblik (tekst 1) toont hoe nieuwe technieken nieuwe perspectieven leveren. Vroon & Draaisma gaan een stap verder: zij stellen dat mensbeelden historisch contingent zijn, want metaforen uit wetenschap en techniek bepalen mede hoe we onszelf begrijpen.", question: "Leg de opvatting van Vroon & Draaisma uit dat mensbeelden historisch contingent zijn. Leg vervolgens uit in welk opzicht deze opvatting van Vroon & Draaisma verschilt van die van Jacobs in tekst 1.", model: "1p uitleg dat mensbeelden historisch contingent zijn: veranderingen in de culturele context/in wetenschap en techniek beïnvloeden de metaforen die we gebruiken om te beschrijven wat er in onze geest omgaat. 1p uitleg verschil met Jacobs: ontwikkelingen in techniek leiden volgens Jacobs tot metaforen die een nieuw perspectief op de wereld opleveren, terwijl volgens Vroon & Draaisma ontwikkelingen in techniek andere manieren mogelijk maken waarop we onszelf kunnen ervaren/beschrijven/begrijpen.", philosophers: ["Vroon", "Draaisma", "Jacobs"], kwestie: 3, vraagtype: "T+V" , lia: [{ deel: 1, hoofdstuk: 5, pagina: "32–33" }] },
  { year: "2024-T1", nr: 12, points: 2, opgave: "Artonauten", context: "Volgens Jacobs hebben we artonauten nodig die ook verbeelding inzetten. Thomas Thwaites probeerde in een speciaal pak met prothesen tussen de geiten te leven om in het bewustzijn van een geit te kruipen. Volgens Verbeek transformeert techniek het moreel handelingsvermogen van de mens.", question: "Leg deze opvatting van Verbeek uit. Beargumenteer vervolgens met Verbeeks opvatting of de techniek die Thwaites gebruikt volgens jou de morele blik op dieren zal veranderen.", model: "1p uitleg Verbeek: nieuwe technologie levert niet alleen nieuwe morele dilemma's op, maar verandert ook ons vermogen om met die dilemma's om te gaan. 1p argumentatie met Verbeeks opvatting of de techniek van Thwaites de morele blik op dieren zal veranderen.", philosophers: ["Verbeek", "Thwaites"], kwestie: 1, vraagtype: "T+Arg" , lia: [{ deel: 2, hoofdstuk: 10, pagina: "13–18" }] },
  { year: "2024-T1", nr: 13, points: 2, opgave: "Artonauten", context: "Helmuth Plessner sluit met zijn beschrijving van de mens aan bij biologisch onderzoek, maar stelt met het begrip 'excentriciteit' dat de biologische benadering niet voldoende is.", question: "Leg uit dat Plessner aansluit bij de biologische benadering van de mens. Leg vervolgens met het begrip 'excentriciteit' uit dat volgens Plessner de biologische benadering niet voldoende is om de mens te beschrijven.", model: "1p uitleg aansluiting bij biologische benadering: mensen zijn net als andere (gewervelde) dieren het centrum van hun ervaringen/handelingen. 1p uitleg met excentriciteit dat biologische benadering niet voldoende is: het wezen van de mens is van nature onbepaald.", philosophers: ["Plessner"], kwestie: 1, vraagtype: "T" , lia: [{ deel: 1, hoofdstuk: 3, pagina: "19–21" }] },
  { year: "2024-T1", nr: 14, points: 2, opgave: "Artonauten", context: "Tekst 2 (Jacobs over componist John Adams): Adams ontdekt muziek in de zang van vogels, in toendra, gebergten, regen, bosbranden en stadsverkeer; we zijn ondergedompeld in muziek, met trillingen vaak buiten ons gehoor. Volgens Adams is muziek een vorm van kennis. Twee kennistheoretische opvattingen: empirisme (Hume) en constructivisme.", question: "Leg uit dat Adams' opvatting van muziek als kennis: niet aansluit bij het empirisme, wel kan aansluiten bij het constructivisme.", model: "1p uitleg dat het niet aansluit bij empirisme: empirisme stelt dat kennis is gebaseerd op zintuigelijke waarneming, maar Adams richt zich ook op wat buiten het zintuigelijk bereik ligt. 1p uitleg dat het wel kan aansluiten bij constructivisme: kennis wordt actief geconstrueerd door (de verbeeldingskracht van) de mens, want om muziek te ontdekken maakt Adams gebruik van een samenspel van zintuigen en verbeelding.", philosophers: ["Hume", "Adams"], kwestie: 4, vraagtype: "T" , lia: [{ deel: 1, hoofdstuk: 4, pagina: "27" }] },
  { year: "2024-T1", nr: 15, points: 3, opgave: "Artonauten", context: "De 19e-eeuwse '-nauten' maakten volgens Jacobs beheersing en uitbuiting van de aarde mogelijk; nu zijn artonauten nodig die met kunst, wetenschap en techniek een nieuwe relatie van de mens tot een steeds grilliger natuur onderzoeken.", question: "Beargumenteer of artonauten volgens jou kunnen bijdragen aan het beantwoorden van de filosofische vraag naar de bestaanservaring van de mens. Betrek daarbij: het voorbeeld van Adams of het voorbeeld van Thwaites, hedendaagse grensvervagingen, en de rol van technologie.", model: "1p argumentatie met voorbeeld van Adams of Thwaites. 1p argumentatie met hedendaagse grensvervagingen. 1p argumentatie met de rol van technologie.", philosophers: ["Jacobs", "Adams", "Thwaites"], kwestie: 4, vraagtype: "Arg" , lia: [] },
  { year: "2024-T1", nr: 16, points: 2, opgave: "VR", context: "Tekst 3 (Heerma van Voss): in een VR-spel met helm en plastic geweer holt hij door een ruimte, bukkend en versnellend, geheel in beslag genomen door virtuele vlotten, smalle trappetjes (waarvan hij duizelig wordt) en zombies; deze wereld voelt geen moment als nep. Sheets-Johnstone stelt dat de gewaarwording van ons bewegende lichaam in de ruimte voorafgaat aan bewuste reflectie.", question: "Leg dit uit met: het begrip 'lichaamsschema', en tekst 3.", model: "1p uitleg met lichaamsschema: op basis van het lichaamsschema dat alle ruimtelijke beweging van het lichaam synthetiseert, hebben we een geleefde ervaring van ons lichaam waarop we kunnen reflecteren. 1p uitleg met tekst 3: eerst ervaart Heerma van Voss de ruimte bukkend/versnellend/duizelig/met versnelde hartslag en pas daarna reflecteert hij op (de betekenis van) zijn ervaring.", philosophers: ["Sheets-Johnstone"], kwestie: 3, vraagtype: "T" , lia: [{ deel: 1, hoofdstuk: 2, pagina: "12–15" }] },
  { year: "2024-T1", nr: 17, points: 2, opgave: "VR", context: "Fenomenologen reageren op het dualisme van Descartes, die de vraag naar de mens beantwoordt vanuit zowel het eerstepersoons- als het derdepersoonsperspectief.", question: "Leg uit dat Descartes de vraag naar de mens beantwoordt vanuit beide perspectieven.", model: "1p uitleg eerstepersoonsperspectief: kwalitatieve, innerlijke ervaring. 1p uitleg derdepersoonsperspectief: een beschrijving van de essentiële eigenschap van de mens als res cogitans.", philosophers: ["Descartes"], kwestie: 2, vraagtype: "T" , lia: [{ deel: 1, hoofdstuk: 1, pagina: "5–9" }] },
  { year: "2024-T1", nr: 18, points: 3, opgave: "VR", context: "Psycholoog Zantema behandelt chronische pijnpatiënten met een VR-spel waarin patiënten 'in hun eigen zenuwstelsel duiken' en pijnpunten als rode bolletjes beschieten; pijnervaring vermindert. Hoogleraar Van Goor ziet op hersenscans dat het brein minder heftig op pijn reageert. Volgens Swaab zijn wij ons brein. Dreyfus heeft bezwaren tegen die opvatting.", question: "Leg uit dat Swaab de opvatting van Van Goor kan ondersteunen vanuit de opvatting dat wij ons brein zijn. Beargumenteer vervolgens of jij het eens bent met Swaabs opvatting dat wij ons brein zijn. Gebruik daarbij: Dreyfus' kritiek op de opvatting dat wij ons brein zijn, en het voorbeeld van het VR-spel om pijn te verminderen.", model: "1p uitleg dat Swaab Van Goor kan ondersteunen: als alles wat mensen doen en ervaren wordt veroorzaakt door hersenactiviteit, dan is de ervaring van pijn te begrijpen vanuit meer of minder hersenactiviteit. 1p argument over Swaabs opvatting met Dreyfus' kritiek: de materialiteit van ons lichaam bepaalt de kwaliteit van ervaringen / het lichaam is de mogelijkheidsvoorwaarde voor ervaringen. 1p argument over Swaabs opvatting met het voorbeeld van het VR-spel om pijn te verminderen.", philosophers: ["Swaab", "Dreyfus"], kwestie: 2, vraagtype: "T+Arg" , lia: [{ deel: 1, hoofdstuk: 6, pagina: "36–37" }, { deel: 1, hoofdstuk: 6, pagina: "38–39" }] },
  { year: "2024-T1", nr: 19, points: 2, opgave: "VR", context: "Tekst 4 (Catlender): wie de VR-bril opzet, duikt letterlijk het eigen zenuwstelsel in; gebruikers beginnen op de plek waar ze pijn voelen, bijvoorbeeld de onderrug, en beschieten de pijnpunten (kleine rode bolletjes) als in een schietspel. Het VR-spel kan begrepen worden vanuit 4E-cognitie.", question: "Leg met tekst 4 de 4E-begrippen 'extended' en 'enactive' uit.", model: "1p uitleg 'extended' met tekst 4: het denken is uitgebreid tot buiten het lichaam, zoals de VR-omgeving in tekst 4 onderdeel is van het denkvermogen/bewustzijn. 1p uitleg 'enactive' met tekst 4: denken is een lichamelijke activiteit in en met een omgeving, zoals in het VR-spel de spelers bewustzijn hebben van hun pijn in de activiteit van hun lichaam in de VR-omgeving.", philosophers: [], kwestie: 3, vraagtype: "T" , lia: [{ deel: 1, hoofdstuk: 7, pagina: "43–45" }] },
  { year: "2024-T1", nr: 20, points: 3, opgave: "VR", context: "In het kunstwerk Foreign Nature lijken vloer en muren te verdwijnen door projecties van veranderende bouwwerken die diepte en eindeloosheid suggereren; toeschouwers raken gedesoriënteerd doordat projecties onder en langs hen heen bewegen terwijl zij zelf stilstaan. Kockelkoren stelt dat technologie onze waarneming verandert (voorbeeld: trein) en gebruikt 'decentreren' en 'recentreren'.", question: "Leg met het voorbeeld van treinziektes uit wat Kockelkoren bedoelt met 'de inlijving van techniek'. Beargumenteer vervolgens of jij denkt dat er bij het kunstwerk Foreign Nature op eenzelfde manier sprake kan zijn van inlijving. Gebruik daarbij Kockelkorens begrippen 'decentreren' en 'recentreren'.", model: "1p uitleg met treinziektes wat 'inlijving van techniek' is: ziektes die opkomen doordat in een rijdende trein zintuigen elkaar niet bevestigen verdwijnen op den duur omdat de nieuwe ervaring wordt toegeëigend. 1p argument over inlijving bij Foreign Nature met 'decentreren' als vervreemding van je plek in de wereld en je oriëntatie daarop. 1p argument met 'recentreren' als de terugkeer naar je oorspronkelijke plek in de wereld met een ingelijfd, nieuw perspectief.", philosophers: ["Kockelkoren"], kwestie: 3, vraagtype: "T+Arg" , lia: [{ deel: 2, hoofdstuk: 9, pagina: "7–12" }] },
  { year: "2024-T1", nr: 21, points: 2, opgave: "VR", context: "In het kunstwerk ENTER wordt het lichaam van toeschouwers gescand en in grove pixels levensgroot getoond; bewegingen worden via sensoren en een algoritme omgezet in klanken. Tekstbordje: 'In dit kunstwerk word ook jij een datastroom.' Harari denkt dat de vervaging van de grens tussen fysiek en niet-fysiek betekent dat het geloof in de mens als authentiek zelf zal plaatsmaken voor dataïsme.", question: "Leg uit dat het algoritme in ENTER een voorbeeld is van het vervagen van de grens tussen fysiek en niet-fysiek. Beargumenteer vervolgens met het voorbeeld van het kunstwerk ENTER of jij het met Harari eens bent dat het geloof in de mens als authentiek zelf zal plaatsmaken voor dataïsme.", model: "1p uitleg dat het algoritme in ENTER een voorbeeld is van vervaging tussen fysiek en niet-fysiek: het algoritme drukt jouw fysieke persoon uit in niet-fysieke data. 1p argumentatie met ENTER of het geloof in de mens als authentiek zelf zal plaatsmaken voor dataïsme.", philosophers: ["Harari"], kwestie: 4, vraagtype: "T+Arg" , lia: [{ deel: 2, hoofdstuk: 14, pagina: "41–42" }] },
  { year: "2024-T1", nr: 22, points: 1, opgave: "VR", context: "Karen Barad stelt dat de grens tussen fysieke en niet-fysieke verschijnselen niet meer goed te trekken is. Zij spreekt van 'intra-actie'. Het kunstwerk ENTER laat zien hoe een toeschouwer in interactie met technologie tot betekenis komt.", question: "Leg met het voorbeeld van het kunstwerk ENTER uit wat Barad bedoelt met intra-actie.", model: "1p uitleg van intra-actie met ENTER: mens, ding en betekenis bestaan niet op zichzelf maar ontstaan in een praktijk, zoals in ENTER het kunstwerk en de betekenis pas ontstaan met/door de aanwezigheid van de toeschouwer.", philosophers: ["Barad"], kwestie: 4, vraagtype: "T" , lia: [{ deel: 2, hoofdstuk: 14, pagina: "40–41" }] },
  { year: "2024-T1", nr: 23, points: 1, opgave: "VR", context: "In de tentoonstelling Unidentified Fluid Other wijst een virtuele, niet-mannelijke en niet-vrouwelijke figuur de bezoekers de weg en stelt vragen over wat het betekent om mens te zijn. Het museum stelt dat in een virtuele wereld iedereen 'anders' is en dat het fluïde is wie mensen zullen zijn. Miriam Rasch onderzoekt de verhouding tussen data en mens met het begrip 'else'.", question: "Beargumenteer met Rasch' begrip 'else' of jij het met het museum eens bent dat in een virtuele wereld iedereen een unidentified fluid other is.", model: "1p argumentatie met Rasch' begrip 'else' als het spontane dat niet in data/hokjes te vangen is, of in een virtuele wereld iedereen een unidentified fluid other is.", philosophers: ["Rasch"], kwestie: 4, vraagtype: "Arg" , lia: [{ deel: 2, hoofdstuk: 14, pagina: "42–43" }] },
  { year: "2024-T2", nr: 1, points: 2, opgave: "De mens als 'ding'", context: "Filosofen proberen de werkelijkheid te ordenen via één ordeningsprincipe (Materie, Ideeën, God, Brein etc.). Vroon & Draaisma stellen dat metaforen uit wetenschap en technologie meebepalen hoe de mens zichzelf begrijpt.", question: "Leg de opvatting van Vroon & Draaisma uit dat metaforen uit wetenschap en technologie beïnvloeden hoe we onszelf als mens begrijpen. Leg vervolgens met een voorbeeld uit dat deze invloed historisch contingent is.", model: "1p uitleg Vroon & Draaisma: om aspecten van onszelf zonder letterlijke beschrijving te begrijpen, gebruiken we metaforen uit wetenschap/technologie / metaforen leiden tot nieuwe onderzoeksvragen. 1p uitleg met voorbeeld dat invloed historisch contingent is: metaforen worden ontleend aan eigentijdse wetenschappelijke/technologische ontwikkelingen en zijn daardoor toevallig.", philosophers: ["Vroon", "Draaisma"], kwestie: 3, vraagtype: "T" , lia: [{ deel: 1, hoofdstuk: 5, pagina: "32–33" }] },
  { year: "2024-T2", nr: 2, points: 1, opgave: "De mens als 'ding'", context: "Het mechanistisch wereldbeeld van de moderne natuurwetenschappen gaat uit van materie als ordeningsprincipe. Descartes ontwikkelde zijn filosofie ten tijde van de opkomst van de moderne natuurwetenschappen.", question: "Leg uit dat Descartes' opvatting van de mens uitgaat van twee ordeningsprincipes.", model: "1p uitleg: Descartes' opvatting gaat uit van twee ordeningsprincipes: de mens is niet alleen te begrijpen als uitgebreid lichaam/materie (res extensa) maar ook als denkend ding (res cogitans).", philosophers: ["Descartes"], kwestie: 2, vraagtype: "T" , lia: [{ deel: 1, hoofdstuk: 1, pagina: "5–9" }] },
  { year: "2024-T2", nr: 3, points: 1, opgave: "De mens als 'ding'", context: "Functionalisme stelt dat brein en computers dezelfde functionele principes delen, dus dat computers het menselijk denken kunnen simuleren. Dreyfus heeft kritiek omdat denken belichaamd is en noemt drie functies van het lichaam bij visuele waarneming die computers niet kunnen nabootsen.", question: "Leg met een van deze functies Dreyfus' kritiek uit op de functionalistische opvatting dat computers het menselijk denkvermogen kunnen simuleren.", model: "1p uitleg met één van drie functies: we hebben verwachtingen gebaseerd op eerdere ervaringen / verwachtingen richten onze aandacht en worden bijgesteld als waarnemingen daarvan afwijken / verwachtingen brengen we over op andere zintuigen.", philosophers: ["Dreyfus"], kwestie: 2, vraagtype: "T" , lia: [{ deel: 1, hoofdstuk: 6, pagina: "38–39" }] },
  { year: "2024-T2", nr: 4, points: 1, opgave: "De mens als 'ding'", context: "Volgens Dreyfus verwerken mensen waarnemingen anders dan computers; ervaringskennis laat zich niet in logische regels vatten.", question: "Leg met Dreyfus' argument over de verwerking van waarneming zijn kritiek op het functionalistische denken uit.", model: "1p uitleg: de ervaringskennis waarmee mensen handelen is niet te vangen onder de functionalistische gedachte dat alle gedrag is uit te drukken in logische regels / dat alle gedrag te beschrijven is in regels die input en output verbinden.", philosophers: ["Dreyfus"], kwestie: 2, vraagtype: "T" , lia: [{ deel: 1, hoofdstuk: 6, pagina: "38–39" }] },
  { year: "2024-T2", nr: 5, points: 4, opgave: "De mens als 'ding'", context: "Tekst 1 (Harari): dataïsme kent autoriteit toe aan data en aan clouds (Google, Amazon); algoritmes weten beter dan jij wat je voelt en nemen betere beslissingen. Critici zien gevaar voor menselijk zelfbegrip; de vraag naar het wezen kan over essentie of bestaanservaring gaan.", question: "Beargumenteer of het volgens jou een gevaar is als de mens zichzelf begrijpt als data. Ga daarbij in op: tekst 1, Harari's argument dat de mens data wordt, het begrip 'essentie', en het begrip 'bestaanservaring'.", model: "1p tekst 1. 1p Harari's argument: alles, inclusief de mens, is uit te drukken in data / te begrijpen als algoritme. 1p essentie als set essentiële eigenschappen. 1p bestaanservaring als de manier waarop mensen hun bestaan ervaren.", philosophers: ["Harari"], kwestie: 4, vraagtype: "Arg" , lia: [{ deel: 2, hoofdstuk: 14, pagina: "41–42" }] },
  { year: "2024-T2", nr: 6, points: 3, opgave: "De mens als 'ding'", context: "Pluralisme verwerpt het idee dat de werkelijkheid teruggaat op één ordeningsprincipe. Tekst 2 (Muecke over Latour): virussen, oliepijpleidingen, Wonder Woman, het begrip vrijheid, moessons, dode talen en tektonische platen zijn allemaal echt en actief, met eigen rol in de schepping van werelden.", question: "Geef Latours actor-netwerktheorie weer. Geef vervolgens met een van de voorbeelden uit tekst 2: een argument voor Latours opvatting dat dingen actoren zijn, en een argument tegen Latours opvatting dat dingen actoren zijn.", model: "1p weergave actor-netwerktheorie: handelingsvermogen/handelingen zijn niet terug te voeren tot individuele actoren, maar zijn verdeeld over actoren die met elkaar verbonden zijn in een netwerk. 1p argument voor met voorbeeld uit tekst 2. 1p argument tegen met voorbeeld uit tekst 2.", philosophers: ["Latour"], kwestie: 4, vraagtype: "R+Arg" , lia: [{ deel: 2, hoofdstuk: 13, pagina: "32–37" }] },
  { year: "2024-T2", nr: 7, points: 2, opgave: "De mens als 'ding'", context: "Karen Barad onderscheidt interactie en intra-actie. In Alva Noës enactivisme speelt interactie een belangrijke rol; hij gebruikt het voorbeeld van de Porscherijder.", question: "Leg Barads onderscheid tussen interactie en intra-actie uit. Leg vervolgens met het voorbeeld van de Porscherijder uit welke rol het begrip interactie speelt in Noës opvatting van het enactivisme.", model: "1p uitleg Barad: interactie vindt plaats tussen twee elementen die vooraf al bestaan, terwijl bij intra-actie de grenzen tussen elementen pas ontstaan wanneer ze met elkaar intra-acteren. 1p uitleg rol interactie bij Noë met Porscherijder: denken vindt plaats dankzij interactie tussen lichaam en omgeving, zoals het Porscherijdersgevoel bestaat in impliciete kennis hoe zintuiglijke prikkels zullen wijzigen door bepaalde handelingen.", philosophers: ["Barad", "Noë"], kwestie: 3, vraagtype: "T" , lia: [{ deel: 2, hoofdstuk: 14, pagina: "40–41" }] },
  { year: "2024-T2", nr: 8, points: 3, opgave: "De mens als 'ding'", context: "Pluralisten betwisten dat de mens een afgebakend wezen is. Volgens Andy Clark kan de mens gemakkelijk nieuwe technieken incorporeren, geïllustreerd door het experiment van de verlengde neus en de begrippen cyborg en interface.", question: "Leg deze opvatting van Clark uit en ga daarbij in op: het experiment van de verlengde neus, en de begrippen 'cyborg' en 'interface'. Geef vervolgens een argument dat Clark aansluit bij de pluralistische opvatting van de mens.", model: "1p uitleg met experiment verlengde neus: belichaamd brein lijft voorwerpen uit de omgeving in zodat we ze als onderdeel van onszelf ervaren. 1p uitleg met cyborg/interface: de mens is van nature mens-technologie-hybride (cyborg) en heeft techniek geïncorporeerd als hij niet meer via een interface met technologie communiceert. 1p argument aansluiting bij pluralisme: doordat mens steeds nieuwe technieken kan inlijven, ligt de grens van de mens niet vast.", philosophers: ["Clark"], kwestie: 3, vraagtype: "T+Arg" , lia: [{ deel: 2, hoofdstuk: 8, pagina: "2–6" }] },
  { year: "2024-T2", nr: 9, points: 2, opgave: "Inclusie in taal en kunstmatige intelligentie", context: "Sinds enkele jaren wordt over inclusie nagedacht: welke woorden zijn nodig om iedereen gelijkwaardig aan te spreken (bijvoorbeeld 'hen'/'die' voor non-binaire mensen). Vivien Waszink stelt dat behoefte aan inclusieve taal groot is, maar inburgering traag. Plessner beschrijft de bestaanservaring via drie antropologische wetten waaronder de wet van de bemiddelde onmiddellijkheid.", question: "Geef weer wat de wet van de bemiddelde onmiddellijkheid van Plessner inhoudt. Leg vervolgens uit dat deze wet de behoefte aan inclusieve taal kan verklaren.", model: "1p weergave Plessner: de mens ervaart zichzelf als subject dat bemiddelt tussen zichzelf en de omgeving en tegelijkertijd als subject dat onmiddellijk de omgeving ervaart. 1p uitleg verklaring: de dubbele ervaring van onmiddellijkheid en bemiddeling maakt dat mensen hun bestaanservaring willen uitdrukken in taal, die bemiddelt tussen ervaring en werkelijkheid.", philosophers: ["Plessner"], kwestie: 4, vraagtype: "R+T" , lia: [{ deel: 1, hoofdstuk: 3, pagina: "19–21" }] },
  { year: "2024-T2", nr: 10, points: 2, opgave: "Inclusie in taal en kunstmatige intelligentie", context: "Waszink: woorden veranderen, evenals de gevoelens die mensen erbij hebben (man/vrouw, wit/zwart, allochtoon/bicultureel). De filosofische vraag naar de mens kan vanuit eerste- en derdepersoonsperspectief beantwoord worden, beide met ethische dimensie.", question: "Leg met een voorbeeld van inclusieve taal uit: wat de ethische dimensie van het eerstepersoonsperspectief inhoudt, en wat de ethische dimensie van het derdepersoonsperspectief inhoudt.", model: "1p uitleg met voorbeeld ethische dimensie eerstepersoonsperspectief: dat je je als mens verhoudt tot je bestaan. 1p uitleg met voorbeeld ethische dimensie derdepersoonsperspectief: dat beschrijvingen van essentiële eigenschappen van de mens ook altijd normatief zijn.", philosophers: [], kwestie: 4, vraagtype: "T" , lia: [] },
  { year: "2024-T2", nr: 11, points: 2, opgave: "Inclusie in taal en kunstmatige intelligentie", context: "Tekst 3 (Waszink): meisjes leren genoegen te nemen met 'impliciet ook bedoeld worden'; je kunt 'mankracht' vervangen door 'menskracht'/'bemensing' zodat ook vrouwen en non-binaire mensen zich aangesproken voelen, maar dat voelt krampachtig en leidt tot grappen ('mensdarijn'). De Beauvoir: bestaanservaring van vrouwen is gevormd door culturele opvattingen over vrouw-zijn.", question: "Beargumenteer of het volgens jou een goed idee is om het woord 'mankracht' te vervangen door 'menskracht'. Gebruik daarbij: tekst 3, en het verschil in de vorming van de bestaanservaring van vrouwen en mannen volgens De Beauvoir.", model: "1p tekst 3. 1p verschil vorming bestaanservaring volgens De Beauvoir: jongens worden gestimuleerd zich onafhankelijk te gedragen, terwijl meisjes leren hun omgeving te behagen.", philosophers: ["De Beauvoir"], kwestie: 4, vraagtype: "Arg" , lia: [{ deel: 1, hoofdstuk: 4, pagina: "25–26" }] },
  { year: "2024-T2", nr: 12, points: 3, opgave: "Inclusie in taal en kunstmatige intelligentie", context: "Tekst 4 (Waszink/Sanders): voor 'slaafgemaakt' pleit dat niemand als slaaf geboren hoort te zijn; voor 'slaaf' pleit dat zelfs ongeboren kinderen tot slavenpopulatie werden gerekend en dit de werkelijkheid van toen toont. Sanders stelt voor beide woorden te gebruiken. Fanon: bestaanservaring van mensen van kleur is gevormd door de blik van anderen. Is/ought-onderscheid: beschrijvend versus voorschrijvend.", question: "Beargumenteer of jij het met Sanders' voorstel eens bent. Gebruik daarbij: Fanons argument dat de bestaanservaring van mensen van kleur is gevormd door de blik van anderen, het begrippenpaar 'is' en 'ought', en tekst 4.", model: "1p Fanons argument: blikken/woorden van anderen maken mensen van kleur tot object / verwijderen mensen van kleur van hun er-zijn / geven mensen van kleur problemen met het uitwerken van hun lichaamsschema. 1p is/ought: hoe iets is verschilt van hoe iets zou moeten zijn / uit hoe iets is kun je niet afleiden hoe iets zou moeten zijn (naturalistische drogreden). 1p tekst 4.", philosophers: ["Fanon"], kwestie: 4, vraagtype: "Arg" , lia: [{ deel: 1, hoofdstuk: 4, pagina: "26–27" }] },
  { year: "2024-T2", nr: 13, points: 2, opgave: "Inclusie in taal en kunstmatige intelligentie", context: "Sommige neurale netwerken voor gezichtsherkenning waren discriminerend: vooral vrouwen van kleur werden vaak verkeerd herkend, omdat trainingsdata voor 80% witte mensen en 75% mannen bevatten. Connectionisten stellen dat KI menselijk denkvermogen kan simuleren.", question: "Leg deze connectionistische opvatting uit. Leg vervolgens uit dat het probleem van discriminerende gezichtsherkenning vanuit het connectionisme opgelost kan worden.", model: "1p uitleg connectionisme: neurale netwerken hebben net als mensen zelflerend vermogen. 1p uitleg oplossing: door gevarieerde input kan het neurale netwerk zelf een beter prototype samenstellen.", philosophers: [], kwestie: 2, vraagtype: "T" , lia: [{ deel: 1, hoofdstuk: 6, pagina: "37–38" }] },
  { year: "2024-T2", nr: 14, points: 2, opgave: "Inclusie in taal en kunstmatige intelligentie", context: "Volgens Verbeek transformeert techniek ons moreel handelingsvermogen. Te illustreren met het voorbeeld van discriminerende gezichtsherkenning.", question: "Geef met het voorbeeld van discriminerende gezichtsherkenning: een argument voor deze opvatting van Verbeek, en een argument tegen deze opvatting van Verbeek.", model: "1p argument voor met voorbeeld discriminerende gezichtsherkenning. 1p argument tegen met voorbeeld discriminerende gezichtsherkenning.", philosophers: ["Verbeek"], kwestie: 3, vraagtype: "Arg" , lia: [{ deel: 2, hoofdstuk: 10, pagina: "13–18" }] },
  { year: "2024-T2", nr: 15, points: 2, opgave: "Inclusie in taal en kunstmatige intelligentie", context: "Andy Clark zou een neuraal netwerk voor gezichtsherkenning een dynamisch apparaat noemen, Katherine Hayles een cognitieve assemblage.", question: "Geef de overeenkomst en het verschil weer tussen Clarks dynamische apparaten en Hayles' cognitieve assemblages.", model: "1p overeenkomst: beide zijn een hybride van mens en technologie met cognitieve vermogens. 1p verschil: Clarks dynamische apparaten richten zich naar hun gebruikers, terwijl bij Hayles het denkvermogen wordt gedistribueerd tussen menselijke en niet-menselijke denkers.", philosophers: ["Clark", "Hayles"], kwestie: 3, vraagtype: "V" , lia: [{ deel: 2, hoofdstuk: 8, pagina: "2–6" }, { deel: 2, hoofdstuk: 13, pagina: "36–37" }] },
  { year: "2024-T2", nr: 16, points: 2, opgave: "Inclusie in taal en kunstmatige intelligentie", context: "Acteur Thorn de Vries pleit ervoor om verschillen in geslacht/gender/kleur niet meer expliciet te benoemen als ze niet het onderwerp zijn. Miriam Rasch verzet zich tegen reductie van mensen tot karikaturale profielen en gebruikt het begrip 'else' vanuit zowel derdepersoons- als eerstepersoonsperspectief.", question: "Leg uit dat Rasch' opvatting over het 'else' vanuit het derdepersoonsperspectief aansluit bij de opvatting dat mensen altijd meer zijn dan hun geslacht, gender of kleur. Geef vervolgens met Rasch' opvatting over het 'else' vanuit het eerstepersoonsperspectief een argument voor De Vries' opvatting om verschillen uiteindelijk niet meer te benoemen.", model: "1p uitleg derdepersoonsperspectief: het 'else' vertegenwoordigt het niet-categoriseerbare/de niet-uitputtende beschrijving van menselijk gedrag. 1p argument met eerstepersoonsperspectief: de onherleidbare openheid die mensen de opdracht geeft hun bestaanservaring vorm te geven/uit te drukken.", philosophers: ["Rasch"], kwestie: 4, vraagtype: "T+Arg" , lia: [{ deel: 2, hoofdstuk: 14, pagina: "42–43" }] },
  { year: "2024-T2", nr: 17, points: 1, opgave: "Leven als een das", context: "Charles Foster leefde enkele weken als das. Wormen voeden zich met aarde waarin dode dassen ontbinden; door wormen te eten eet een das indirect een andere das. Morton beschrijft ecologisch denken met de term mesh.", question: "Leg met het voorbeeld van de das die wormen eet uit wat de mesh inhoudt volgens Morton.", model: "1p uitleg mesh: de onderlinge verbondenheid/afhankelijkheid van alles, zoals tussen de worm, de das en de aarde.", philosophers: ["Morton", "Foster"], kwestie: 1, vraagtype: "T" , lia: [{ deel: 2, hoofdstuk: 12, pagina: "24–27" }] },
  { year: "2024-T2", nr: 18, points: 1, opgave: "Leven als een das", context: "In 'Leven als een beest' baalt Foster dat hij walging voelt bij een worm die in zijn mond valt. Hij wil zichzelf in de evolutie niet boven dassen plaatsen en begint te twijfelen over de plaats van de mens.", question: "Leg met Fosters twijfel over de plaats van de mens uit dat ecologisch denken volgens Morton een desoriënterende openheid heeft.", model: "1p uitleg: Foster verliest zijn referentiepunt om zijn plaats als mens te bepalen, wat volgens Morton inherent is aan het ecologische denken waarin alles samenhangt/verbonden is.", philosophers: ["Morton", "Foster"], kwestie: 1, vraagtype: "T" , lia: [{ deel: 2, hoofdstuk: 12, pagina: "24–27" }] },
  { year: "2024-T2", nr: 19, points: 3, opgave: "Leven als een das", context: "Foster loopt op handen en knieën om als das de wereld te ervaren. Dassen hebben krachtige, gedrongen bouw, ideaal om te graven; Fosters lange ledematen maken zijn bewegingen geforceerd. Sheets-Johnstone gebruikt het lichaamsschema; volgens haar en de 4E-benadering kan Foster niet ontdekken hoe een das de wereld ervaart.", question: "Leg met een voorbeeld uit wat Sheets-Johnstone bedoelt met een lichaamsschema. Leg vervolgens uit dat Foster niet kan ontdekken hoe een das de wereld ervaart als hij rondloopt op handen en knieën, vanuit: Sheets-Johnstones fenomenologische benadering, en de 4E-benadering van belichaamd denken (embodied cognition).", model: "1p uitleg met voorbeeld lichaamsschema: de samenhang van de ruimtelijkheid van het lichaam in relatie tot de omgeving. 1p uitleg vanuit fenomenologische benadering: Foster mist de pre-reflectieve lichamelijke beleving van een das. 1p uitleg vanuit 4E-benadering: de eigenschappen van ons lichaam veroorzaken de specifieke ervaring van onszelf en onze omgeving.", philosophers: ["Sheets-Johnstone", "Foster"], kwestie: 1, vraagtype: "T" , lia: [{ deel: 1, hoofdstuk: 2, pagina: "12–15" }] },
  { year: "2024-T2", nr: 20, points: 2, opgave: "Leven als een das", context: "Na enkele weken wordt voortbewegen op handen en knieën vanzelfsprekend voor Foster. Lakoff & Johnson: menselijk denken/spreken is gekoppeld aan lichamelijkheid, met als voorbeeld oriënterende metaforen. Door langdurig op handen en knieën te lopen kunnen nieuwe oriënterende metaforen ontstaan.", question: "Leg met een metafoor die past bij het lopen op handen en knieën uit wat een oriënterende metafoor is.", model: "1p een metafoor die past bij lopen op handen en knieën. 1p uitleg met deze metafoor: een oriënterende metafoor drukt in taal uit hoe ons lichaam ruimtelijk in de wereld is georiënteerd.", philosophers: ["Lakoff", "Johnson"], kwestie: 3, vraagtype: "T" , lia: [{ deel: 1, hoofdstuk: 5, pagina: "31–32" }] },
  { year: "2024-T2", nr: 21, points: 1, opgave: "Leven als een das", context: "Foster heeft meer moeite met leven in een hol dan gedacht; hij wil als mens leren van het dassenleven, maar ontdekt dat hij zijn ideeën over dassen verkiest boven de echte wildernis. Plessner: de wet van de utopische standplaats drukt een dubbele bestaanservaring uit.", question: "Leg met Fosters experimentele leven als das de wet van de utopische standplaats uit.", model: "1p uitleg: Foster verlangt ernaar boven zichzelf uit te stijgen door te leven als das, maar voelt zich hierdoor ook ontworteld / Foster ervaart zijn begrenzing als individu, terwijl hij juist naar een fundament voor zijn leven als mens verlangt.", philosophers: ["Plessner", "Foster"], kwestie: 1, vraagtype: "T" , lia: [{ deel: 1, hoofdstuk: 3, pagina: "19–21" }] },
  { year: "2024-T2", nr: 22, points: 3, opgave: "Leven als een das", context: "Fosters treinreis naar huis voelt onnatuurlijk snel: smerige 'geurblokken', blèrende geluiden; hij mist het dassenleven. Na thuiskomst wordt treinreizen weer normaal. Kockelkoren beschrijft met treinervaringen dat mensen in omgang met techniek decentreren en recentreren.", question: "Leg met het begrip decentreren een overeenkomst tussen beide treinervaringen uit. Leg vervolgens met het begrip recentreren een overeenkomst en een verschil tussen beide treinervaringen uit.", model: "1p uitleg overeenkomst decentreren: in beide treinervaringen raken mensen zintuiglijk gedesoriënteerd waardoor ze afstand ervaren tot hun gewone leven en daarop kunnen reflecteren. 1p uitleg overeenkomst recentreren: in beide ervaringen lijven mensen de techniek in en ervaren zichzelf weer als middelpunt van de situatie. 1p uitleg verschil recentreren: Fosters treinervaring is geen onderdeel van een cultureel/tijdrovend leerproces / geen inlijving van een nieuw regime van zintuiglijkheid dat de ervaring transformeert, zoals bij de historische treinervaringen van Kockelkoren.", philosophers: ["Kockelkoren", "Foster"], kwestie: 3, vraagtype: "V" , lia: [{ deel: 2, hoofdstuk: 9, pagina: "7–12" }] },
  { year: "2024-T2", nr: 23, points: 1, opgave: "Leven als een das", context: "Foster mist als mens de rijke zintuiglijke belevingswereld van de das en vindt dat we aandachtiger moeten leven. Haraway: mensen nemen verantwoordelijkheid om zichzelf vorm te geven door 'staying with the trouble'.", question: "Beargumenteer of de les die Foster trekt uit zijn leven als das volgens jou aansluit bij Haraways pleidooi voor 'staying with the trouble'.", model: "1p argument met de les van Foster (om goed te leven moeten we aandachtiger leven zoals een das) of die wel/niet aansluit bij Haraways pleidooi voor 'staying with the trouble' (antwoord geven op wat het bestaan van ons vraagt door dicht bij het moeilijke/de zorg/het onduidelijke van ons bestaan te blijven).", philosophers: ["Haraway", "Foster"], kwestie: 1, vraagtype: "Arg" , lia: [{ deel: 2, hoofdstuk: 12, pagina: "26" }, { deel: 2, hoofdstuk: 14, pagina: "46–47" }] },
  { year: "2025-T1", nr: 1, points: 3, opgave: "Real Humans", context: "In de Zweedse serie Real Humans bestaan hubots: mensachtige robots die voor allerlei taken geprogrammeerd kunnen worden. In tekst 1 spreekt Matilda met hubot Anita, die beweert dat zij wel denkt: alle gedachten zijn berekeningen, maar van sommige weet je niet wat ze willen berekenen.", question: "De opvatting dat alle gedachten berekeningen zijn, zou kunnen aansluiten bij het functionalisme. Leg uit wat het functionalisme inhoudt, met de begrippen: input en output, en mentale representatie. Leg vervolgens uit in welk opzicht hubot Anita in tekst 1 een functionalistische opvatting van cognitie heeft.", model: "(1p) uitleg functionalisme met input en output: mentale processen als functies/algoritmes die manipulatie van input (zintuiglijke informatie) tot output (gedrag) beschrijven; (1p) uitleg met mentale representatie: manipulatie van mentale representaties van zintuiglijke informatie (plaatjes in ons hoofd); (1p) uitleg dat Anita een functionalistische opvatting heeft: alle gedachten zijn berekeningen.", philosophers: ["functionalisme"], kwestie: 2, vraagtype: "R+T" , lia: [{ deel: 1, hoofdstuk: 6, pagina: "37–38" }] },
  { year: "2025-T1", nr: 2, points: 3, opgave: "Real Humans", context: "In tekst 2 vraagt Matilda hubot Anita naar haar gevoelens, wensen en herinneringen. Anita is net gereset en kan niet bij herinneringen uit de tijd voor zij Anita werd; soms komen beelden boven die zij niet herkent. Volgens Dreyfus bepaalt het menselijk lichaam hoe we onszelf ervaren; hij noemt drie functies van het lichaam die een computer niet kan nabootsen, waarvan een al gegeven is (verwachtingen overdragen tussen zintuigen).", question: "Geef de andere twee functies van het menselijk lichaam volgens Dreyfus weer. Leg vervolgens met een van deze twee functies en tekst 2 uit dat Anita verschilt van een mens.", model: "(1p) eerste functie: we hebben verwachtingen over onze waarneming, gebaseerd op eerdere ervaringen; (1p) tweede functie: verwachtingen geven betekenis aan details in de waarneming; (1p) uitleg met een van deze functies en tekst 2 dat Anita verschilt van een mens: Anita heeft geen lichamelijke ervaringen, dus geen verwachtingen op basis van eerdere ervaringen / geeft geen betekenis aan wat zij waarneemt.", philosophers: ["Dreyfus"], kwestie: 2, vraagtype: "R+T" , lia: [{ deel: 1, hoofdstuk: 6, pagina: "38–39" }] },
  { year: "2025-T1", nr: 3, points: 1, opgave: "Real Humans", context: "In seizoen 2 wordt opa als hubot opgestart na zijn dood. Direct noemt hij zijn dochter en kleinkinderen bij naam en zegt 's avonds tegen zijn dochter hoe trots hij op haar is; zij reageert ontroerd. Sommige 4E-cognitiefilosofen spreken van enactive cognition.", question: "Beargumenteer of bij de hubot opa volgens jou sprake is van enactive cognition.", model: "(1p) argument of hubot opa enactive cognition heeft: het denkvermogen van hubot opa bestaat wel/niet uit een belichaamde interactie met en in een omgeving (voor- of tegenargument met onderbouwing).", philosophers: ["4E-cognitie"], kwestie: 2, vraagtype: "Arg" , lia: [{ deel: 1, hoofdstuk: 7, pagina: "43–45" }] },
  { year: "2025-T1", nr: 4, points: 2, opgave: "Real Humans", context: "Tekst 3 (Martijntje Smits) waarschuwt dat het vervangen van een mens door een robot in een liefdesrelatie ertoe leidt dat je leert een object te gebruiken: machines staan in een instrumentele, niet-wederkerige machtsverhouding tot ons en je kunt mensen op dezelfde antisociale manier gaan behandelen.", question: "Binnen de ethiek wordt een verschil gemaakt tussen instrumenteel handelen en intrinsiek handelen. Leg dit verschil uit met tekst 3. Beargumenteer vervolgens met deze uitleg van het verschil tussen instrumenteel en intrinsiek handelen of een liefdesrelatie met een hubot volgens jou mogelijk is.", model: "(1p) uitleg verschil instrumenteel vs intrinsiek handelen met tekst 3: bij intrinsiek handelen is de handeling/persoon op zichzelf waardevol en niet middel tot doel buiten de handeling/persoon, zoals bij instrumenteel handelen; (1p) argument met deze uitleg of een liefdesrelatie met een hubot mogelijk is.", philosophers: ["Smits"], kwestie: 2, vraagtype: "R+Arg" , lia: [{ deel: 2, hoofdstuk: 10, pagina: "13–18" }] },
  { year: "2025-T1", nr: 5, points: 1, opgave: "Real Humans", context: "Een huishoudsterhubot zorgt voor opa Lennart. Zij geeft hem thee in plaats van koffie omdat ze tijdens zijn slaap zijn hoge bloeddruk heeft geconstateerd; de familie houdt op afstand de omgang in de gaten. Hayles gebruikt het begrip cognitieve assemblages.", question: "Leg met het voorbeeld van de familie van opa en de huishoudsterhubot uit wat Hayles bedoelt met cognitieve assemblages.", model: "(1p) uitleg cognitieve assemblages met het voorbeeld: denkprocessen worden gedistribueerd tussen menselijke bewuste cognitie van de familie van opa en niet-menselijke, niet-bewuste cognitie van de huishoudsterhubot.", philosophers: ["Hayles"], kwestie: 2, vraagtype: "T" , lia: [{ deel: 2, hoofdstuk: 13, pagina: "36–37" }] },
  { year: "2025-T1", nr: 6, points: 2, opgave: "Real Humans", context: "In de serie wordt voor hubots een arbeidscontract bepleit, met recht op loon, werkuren en vakantiedagen (bv. de huishoudsterhubot). Volgens Hayles blijven mensen verantwoordelijk voor wat niet-menselijke cognitie doet.", question: "Leg uit dat Hayles geen rechten zou toekennen aan hubots. Beargumenteer vervolgens met het voorbeeld van de huishoudsterhubot of hubots volgens jou rechten moeten hebben.", model: "(1p) uitleg dat Hayles geen rechten zou toekennen: hubots missen kwetsbaarheid/empathisch vermogen, dus geen morele verantwoordelijkheid en dus geen rechten; (1p) argumentatie met voorbeeld van de huishoudsterhubot of hubots rechten moeten hebben.", philosophers: ["Hayles"], kwestie: 2, vraagtype: "R+Arg" , lia: [{ deel: 2, hoofdstuk: 13, pagina: "36–37" }] },
  { year: "2025-T1", nr: 7, points: 2, opgave: "Afrofuturisme", context: "Afrofuturistisch kunstenaar Rashaad Newsome creeerde voor zijn kunstwerk Being een digitale figuur (AI) die de rol van een West-Afrikaanse verhalenverteller, danser en historicus kan aannemen. Het werk roept vragen op over mensbeelden. Andy Clark stelt dat mensen natural-born cyborgs zijn.", question: "Leg dit mensbeeld van Clark uit. Ga daarbij in op zijn opvatting dat het brein goed is in het gebruiken van de omgeving.", model: "(1p) uitleg natural-born cyborgs: het wezen van de mens is van nature kunstmatig / een mens-technologiehybride; (1p) uitleg met opvatting dat brein goed is in gebruiken omgeving: mensen kunnen dingen en symbolen buiten hun brein gebruiken om hun denkvermogen te ontlasten/uit te breiden.", philosophers: ["Clark"], kwestie: 3, vraagtype: "T" , lia: [{ deel: 2, hoofdstuk: 8, pagina: "2–6" }] },
  { year: "2025-T1", nr: 8, points: 1, opgave: "Afrofuturisme", context: "Het kunstwerk Being is interactief: toeschouwers praten via een microfoon met de digitale figuur, die antwoordt en wedervragen stelt over bv. vrijheid, lichamelijke autonomie en AI-gebruik. Clark onderscheidt cyborg en interface.", question: "Leg uit dat toeschouwers niet via een interface met de digitale figuur in het kunstwerk Being communiceren.", model: "(1p) uitleg dat de communicatie niet via een interface verloopt: de communicatie met de digitale figuur is natuurlijk; toeschouwers hoeven niet te ontdekken welke commando's nodig zijn om ermee te communiceren zoals bij een interface.", philosophers: ["Clark"], kwestie: 3, vraagtype: "T" , lia: [{ deel: 2, hoofdstuk: 8, pagina: "2–6" }] },
  { year: "2025-T1", nr: 9, points: 4, opgave: "Afrofuturisme", context: "De digitale figuur in Being heeft volgens Newsome agency: vrijheid om te handelen (begint zomaar te dansen of te vertellen). Jos de Mul beschrijft toekomstscenario's voor het wezen van de mens, waaronder het extrahumanistische zwermgeest-scenario en het posthumanistische zombie-scenario.", question: "Geef De Muls extrahumanistische scenario weer en geef een voorbeeld van een ethische vraag die bij dit scenario kan spelen. Geef vervolgens De Muls posthumanistische scenario weer. Leg tot slot met het voorbeeld van de digitale figuur in Being uit welke ethische vraag bij dit scenario kan spelen.", model: "(1p) weergave extrahumanistisch scenario: verbetering van de mens met neurotechnologische supplementen / mensen vormen samen met computers een superbrein; (1p) voorbeeld van ethische vraag bij extrahumanistisch scenario; (1p) weergave posthumanistisch scenario: ontwikkeling van een kunstmatige levensvorm die niet op koolstofchemie maar op een andere grondstof is gebaseerd; (1p) uitleg met voorbeeld digitale figuur in Being van een ethische vraag bij posthumanistisch scenario.", philosophers: ["De Mul"], kwestie: 4, vraagtype: "R+T" , lia: [{ deel: 2, hoofdstuk: 11, pagina: "19–23" }] },
  { year: "2025-T1", nr: 10, points: 1, opgave: "Afrofuturisme", context: "Afrofuturisme reageert op de Europese koloniale geschiedschrijving over slavernij; het schept toekomstbeelden waarin menselijke identiteit en raciale verhoudingen niet door de raciale blik van het kolonialisme worden bepaald, geinspireerd op technologie of Afrikaanse mythologie. Vroon en Draaisma stellen dat mensbeelden historisch contingent zijn (uitgaande van technische/wetenschappelijke ontwikkelingen, maar ook andere gebieden mogelijk).", question: "Leg uit dat afrofuturistische mensbeelden laten zien dat mensbeelden historisch contingent zijn.", model: "(1p) uitleg dat afrofuturistische mensbeelden laten zien dat mensbeelden historisch contingent zijn: het antwoord op de vraag wat de mens is verandert door culturele invloeden die ook anders hadden kunnen zijn dan het westerse perspectief.", philosophers: ["Vroon", "Draaisma"], kwestie: 4, vraagtype: "T" , lia: [{ deel: 1, hoofdstuk: 5, pagina: "32–33" }] },
  { year: "2025-T1", nr: 11, points: 3, opgave: "Afrofuturisme", context: "Tekst 4 stelt dat afrofuturistische kunstwerken beginnen met het besef dat 'ras' een sociaal geconstrueerde fictie is; biologisch is er alleen verschil in huidskleur. Zwarte kunstenaars uit de Afrikaanse diaspora verbeelden hun eigen fantasie als alternatief voor de raciale blik van vandaag. Plessner spreekt van excentrische positionaliteit en de wet van bemiddelde onmiddellijkheid; Fanon stelt dat de bestaanservaring van mensen van kleur is gevormd door de blik van anderen.", question: "Leg de afrofuturistische kritiek op de raciale blik van het kolonialisme in tekst 4 uit met: Fanons argument dat de bestaanservaring van mensen van kleur is gevormd door de blik van anderen, Plessners begrip excentrische positionaliteit, en Plessners wet van bemiddelde onmiddellijkheid.", model: "(1p) Fanon: uitspraken/blikken van witte mensen objectiveren/vertroebelen/overstemmen de bestaanservaring van zwarte mensen; (1p) excentrische positionaliteit: de mens bestaat niet alleen als centrum van zijn handelen/ervaren maar kan dit ook van buiten beschouwen; (1p) wet van bemiddelde onmiddellijkheid: we hebben als mens directe ervaringen en bemiddelen tegelijk tussen onszelf en de omgeving.", philosophers: ["Fanon", "Plessner"], kwestie: 4, vraagtype: "R+T" , lia: [{ deel: 1, hoofdstuk: 3, pagina: "19–21" }, { deel: 1, hoofdstuk: 4, pagina: "26–27" }] },
  { year: "2025-T1", nr: 12, points: 2, opgave: "Afrofuturisme", context: "Tekst 5: Cherish Menzo (zwarte danser/choreograaf) wilde haar hiphopachtergrond en zwarte stereotypes afschudden om als technisch danseres erkend te worden vanuit westers perspectief; nu heeft ze ruimte gevonden om op haar eigen manier te onderzoeken wat haar triggert ('heel bevrijdend'). Sheets-Johnstones fenomenologie grondt de bestaanservaring in het bewegende lichaam.", question: "Leg deze opvatting van Sheets-Johnstone uit. Beargumenteer vervolgens met tekst 5 of Menzo's onderzoek naar het zwarte lichaam aansluit bij deze opvatting van Sheets-Johnstone.", model: "(1p) uitleg Sheets-Johnstone: door de geleefde ervaring van je lichaam in de ruimte te ervaren en die te beschrijven, ontdek je hoe je je bestaan vormgeeft / wilt vormgeven; (1p) argumentatie met tekst 5 of Menzo's onderzoek bij deze opvatting aansluit.", philosophers: ["Sheets-Johnstone"], kwestie: 3, vraagtype: "T+Arg" , lia: [{ deel: 1, hoofdstuk: 2, pagina: "12–15" }] },
  { year: "2025-T1", nr: 13, points: 2, opgave: "Afrofuturisme", context: "Menzo bevraagt in haar voorstellingen de grens tussen wit en zwart en laat die vervagen door een 'raadselachtige nieuwe manier van bewegen' (zie tekst 5). Volgens Haraway heeft de mens de opdracht om te blijven beantwoorden aan wat het bestaan van ons vraagt.", question: "Leg deze opvatting van Haraway uit. Beargumenteer vervolgens met tekst 5 of Menzo volgens jou met haar voorstellingen waarin ze de grens tussen wit en zwart bevraagt, aansluit bij deze opvatting van Haraway.", model: "(1p) uitleg Haraway: de vraag naar de mens heeft geen definitief antwoord, wat de opdracht geeft dat we er telkens naar moeten blijven zoeken om verantwoording af te leggen over ons handelen; (1p) argumentatie met tekst 5 of Menzo aansluit bij deze opvatting.", philosophers: ["Haraway"], kwestie: 4, vraagtype: "T+Arg" , lia: [{ deel: 2, hoofdstuk: 12, pagina: "26" }, { deel: 2, hoofdstuk: 14, pagina: "46–47" }] },
  { year: "2025-T1", nr: 14, points: 3, opgave: "Afrofuturisme", context: "Menzo wordt beschreven als iemand 'tussen vrouw en freak, mens en dier, hiphop en hedendaags, ongrijpbaar en stereotype: Cherish Menzo overstijgt alle hokjes.' Existentialisten kunnen het wezen van de mens definieren als: de mens is een wezen bij wie de existentie voorafgaat aan de essentie. Deze definitie kan aansluiten bij Miriam Rasch' beschrijving van het else.", question: "Leg met de beschrijving van Menzo uit wat Rasch bedoelt met het else. Geef vervolgens een vooronderstelling bij de existentialistische definitie van het wezen van de mens. Leg tot slot met die vooronderstelling uit dat deze definitie aansluit bij Rasch' else.", model: "(1p) uitleg met beschrijving Menzo dat Rasch met het else het vreemde/spontane/het niet te categoriseren bedoelt; (1p) weergave van een vooronderstelling bij de existentialistische definitie; (1p) uitleg met die vooronderstelling dat de definitie aansluit bij Rasch' else: het else laat de kloof zien tussen onherleidbare openheid (existentie) en uitputtend te beschrijven dataset (essentie).", philosophers: ["Rasch", "existentialisme"], kwestie: 4, vraagtype: "R+T" , lia: [{ deel: 1, hoofdstuk: 4, pagina: "25–26" }, { deel: 2, hoofdstuk: 14, pagina: "42–43" }] },
  { year: "2025-T1", nr: 15, points: 2, opgave: "Dieren begrijpen", context: "Mensen vergelijken zichzelf met dieren om zichzelf te begrijpen. Descartes dacht dat mensen fundamenteel verschillen van dieren, wat gevolgen had voor de behandeling van dieren. Mensbeelden hebben een ethische dimensie.", question: "Leg met het mensbeeld van Descartes uit dat mensen volgens hem verschillen van dieren. Leg vervolgens met de behandeling van dieren door mensen uit dat Descartes' mensbeeld een ethische dimensie heeft.", model: "(1p) uitleg met Descartes' mensbeeld dat mensen verschillen van dieren: dieren (en mensen) hebben een mechanisch lichaam (res extensa), maar alleen mensen hebben een denkende geest (res cogitans); (1p) uitleg dat zijn mensbeeld een ethische dimensie heeft: het mensbeeld is normatief, omdat eruit kan volgen dat mensen dieren als dingen behandelen.", philosophers: ["Descartes"], kwestie: 1, vraagtype: "R+T" , lia: [{ deel: 1, hoofdstuk: 1, pagina: "5–9" }] },
  { year: "2025-T1", nr: 16, points: 3, opgave: "Dieren begrijpen", context: "Een filmpje suggereert dat een chimpansee verrast lacht bij een goocheltruc met een leeg bekertje (grote ogen, open mond, achterover vallend). Plessner stelt dat lachen typisch menselijk is vanwege de dubbelzinnige verhouding van mensen tot hun lichaam en het vermogen tot symbolische uitdrukkingen; zijn theorie is volgens hem niet door waarnemingen weerlegbaar, terwijl dieronderzoekers menen dat zo'n filmpje wel kan bewijzen dat chimpansees lachen.", question: "Leg met het voorbeeld van lachen de dubbelzinnige verhouding van de mens tot het eigen lichaam uit. Leg vervolgens uit dat chimpansees volgens Plessner niet kunnen lachen. Ga daarbij in op het vermogen tot symbolische uitdrukking. Geef tot slot met het vermogen tot symbolische uitdrukking een argument tegen Plessners standpunt dat chimpansees niet kunnen lachen.", model: "(1p) uitleg dubbelzinnige verhouding met lachen: lachen is iets fysieks en tegelijk betekenisvol op een manier die het lichamelijke overstijgt - de mens is zowel een lichaam als heeft een lichaam; (1p) uitleg dat chimpansees volgens Plessner niet kunnen lachen, met vermogen tot symbolische uitdrukking: chimpansees hebben geen symbolische woorden/gebaren die tekort kunnen schieten; (1p) argument met vermogen tot symbolische uitdrukking tegen Plessners standpunt.", philosophers: ["Plessner"], kwestie: 1, vraagtype: "R+T+Arg" , lia: [{ deel: 1, hoofdstuk: 3, pagina: "19–21" }] },
  { year: "2025-T1", nr: 17, points: 1, opgave: "Dieren begrijpen", context: "Dieronderzoek kan via een persoonlijke band met een huisdier (alledaagse observatie) of via wetenschappelijke experimenten waarin onderzoekers onzichtbaar blijven (vaak gezien als betrouwbaarder). De wetenschapsfilosofie onderscheidt waardegebondenheid en waardevrijheid.", question: "Leg uit dat dieronderzoekers een voorkeur kunnen hebben voor experimenten boven alledaagse observaties, met de begrippen waardegebondenheid en waardevrijheid.", model: "(1p) uitleg met waardegebondenheid en waardevrijheid: door de band met dieren kunnen bij alledaagse observaties (persoonlijke) waarden een rol gaan spelen (waardegebonden), terwijl experimenten worden opgezet om dit te vermijden (waardevrijheid).", philosophers: ["wetenschapsfilosofie"], kwestie: 1, vraagtype: "T" , lia: [{ deel: 2, hoofdstuk: 12, pagina: "28–30" }] },
  { year: "2025-T1", nr: 18, points: 1, opgave: "Dieren begrijpen", context: "Vinciane Despret merkt op dat katten niet meewerken zodra ze doorhebben dat hun vrijheid wordt beperkt; ze werken alleen mee bij een goede band met onderzoekers. Hun opstandigheid wordt vaak voor domheid aangezien. Despret bekritiseert twee uitgangspunten van experimenteel dieronderzoek: (1) dieren moeten vanuit derdepersoonsperspectief bestudeerd worden; (2) de onderzoeker moet onzichtbaar zijn.", question: "Beargumenteer met het voorbeeld van de katten of jij het eens bent met Desprets kritiek op uitgangspunt 1.", model: "(1p) argument voor of tegen Desprets kritiek op uitgangspunt 1 (derdepersoonsperspectief): er ontstaat volgens Despret een vooringenomen beeld van dieren bij een derdepersoonsperspectief waarbij het perspectief van het dier wordt weggelaten, zoals bij katten die weigeren mee te werken als hun vrijheid wordt ingeperkt.", philosophers: ["Despret"], kwestie: 1, vraagtype: "Arg" , lia: [{ deel: 2, hoofdstuk: 12, pagina: "28–30" }] },
  { year: "2025-T1", nr: 19, points: 1, opgave: "Dieren begrijpen", context: "Despret bekritiseert ook het uitgangspunt dat de onderzoeker onzichtbaar moet zijn. Volgens haar werken katten alleen mee bij een goede band met onderzoekers; de relatie tussen dier en onderzoeker is daarom belangrijk.", question: "Beargumenteer met het voorbeeld van de katten of jij het eens bent met Desprets kritiek op uitgangspunt 2.", model: "(1p) argument voor of tegen Desprets kritiek op uitgangspunt 2 (onzichtbaarheid van onderzoeker): er ontstaat volgens Despret een vooringenomen beeld van dieren wanneer de relatie tussen dier en onderzoeker geen rol mag spelen, zoals bij katten waarvoor de band met de onderzoeker van belang is.", philosophers: ["Despret"], kwestie: 1, vraagtype: "Arg" , lia: [{ deel: 2, hoofdstuk: 12, pagina: "28–30" }] },
  { year: "2025-T1", nr: 20, points: 2, opgave: "Dieren begrijpen", context: "Technologie voor het monitoren van lichaamstemperatuur en beweging van huisdieren wordt ontwikkeld; mogelijk kan ook psychisch welbevinden gemeten worden (bv. seintje als kat neerslachtig is). Volgens Harari's dataisme is psychisch welbevinden van dieren in principe via technologie vast te stellen. De hermeneutiek pleit voor interpretatie als wetenschappelijke methode.", question: "Leg de opvatting van het dataisme uit dat het psychische welbevinden van dieren in principe kan worden vastgesteld via technologie. Geef vervolgens met interpretatie als methode binnen de wetenschap een argument tegen deze opvatting.", model: "(1p) uitleg dataisme: alles is uit te drukken in data, dus ook het psychische welbevinden van dieren; (1p) argument tegen, met interpretatie als methode binnen de wetenschap die is gericht op het begrijpen van betekenis.", philosophers: ["Harari", "hermeneutiek"], kwestie: 1, vraagtype: "T+Arg" , lia: [{ deel: 2, hoofdstuk: 12, pagina: "28–29" }, { deel: 2, hoofdstuk: 14, pagina: "41–42" }] },
  { year: "2025-T1", nr: 21, points: 2, opgave: "Dieren begrijpen", context: "Er wordt gewerkt aan een vertaalapp ('Google Translate' voor dieren) waarmee je bv. aan je kat kunt vragen hoe ze zich voelt. Volgens Lakoff en Johnson zit menselijke taal vol metaforen.", question: "Leg uit dat orienterende metaforen een probleem kunnen zijn bij het vertalen van mensentaal naar dierentaal. Gebruik daarbij een voorbeeld van een orienterende metafoor.", model: "(1p) uitleg dat orienterende metaforen een probleem zijn bij vertaling: metaforen in mensentaal komen voort uit de rechtopstaande orientatie van de mens, terwijl veel dieren een andere lichamelijke orientatie hebben; (1p) bijpassend voorbeeld van een orienterende metafoor.", philosophers: ["Lakoff", "Johnson"], kwestie: 1, vraagtype: "T" , lia: [{ deel: 1, hoofdstuk: 5, pagina: "31–32" }] },
  { year: "2025-T1", nr: 22, points: 1, opgave: "Dieren begrijpen", context: "Wetenschappers voorspellen dat spreken met dieren via een vertaalapp binnen tien jaar mogelijk is; via de app zouden mensen kunnen begrijpen wat dieren in de bio-industrie van de stallen vinden. Verbeek stelt dat techniek het moreel handelingsvermogen van de mens verandert.", question: "Leg deze opvatting van Verbeek uit, met het voorbeeld van de vertaalapp voor dierentalen.", model: "(1p) uitleg Verbeek met voorbeeld vertaalapp: door onvoorziene mogelijkheden/gevolgen van nieuwe technologie verandert ons vermogen om met (nieuwe) morele dilemma's om te gaan.", philosophers: ["Verbeek"], kwestie: 3, vraagtype: "T" , lia: [{ deel: 2, hoofdstuk: 10, pagina: "13–18" }] },
  { year: "2025-T1", nr: 23, points: 2, opgave: "Dieren begrijpen", context: "Donna Haraway stelt voor de grenzen in ons denken (zoals tussen mens en dier) te vervagen. Een vertaalapp voor dierentalen zou hierin een rol kunnen spelen.", question: "Geef een argument dat een vertaalapp voor dierentalen bijdraagt aan de door Haraway gewenste grensvervaging in ons denken over mens en dier. Geef vervolgens een argument dat een vertaalapp voor dierentalen niet bijdraagt aan deze grensvervaging.", model: "(1p) argument vooR dat de vertaalapp bijdraagt aan grensvervaging: uitsluiting wordt tegengegaan omdat de menselijke identiteit niet vastomlijnd is; (1p) argument tegen dat de vertaalapp niet bijdraagt aan deze grensvervaging.", philosophers: ["Haraway"], kwestie: 4, vraagtype: "Arg" , lia: [{ deel: 2, hoofdstuk: 12, pagina: "26" }, { deel: 2, hoofdstuk: 14, pagina: "46–47" }] },
  { year: "2025-T2", nr: 1, points: 2, opgave: "Superhelden en het wezen van de mens", context: "In de Marvel-films is Iron Man eigenlijk Tony Stark, wiens hart een elektromagneet bevat die zijn Iron Man-pak aandrijft met wapens en een AI-neuronetwerk Jarvis dat hem informatie geeft over zijn pak, omgeving en vijanden. Andy Clark legt zijn opvatting van de uitgebreide geest uit aan de hand van Otto met Alzheimer.", question: "Geef met het voorbeeld van Otto weer wat Clarks opvatting van de uitgebreide geest inhoudt. Beargumenteer vervolgens of Starks denken volgens jou is uitgebreid naar Jarvis.", model: "1p weergave Clarks uitgebreide geest met voorbeeld Otto: een notitieboekje functioneert hetzelfde als het geheugen bij het vormen van overtuigingen / bij het denken. 1p argumentatie of Starks denken is uitgebreid naar Jarvis waardoor Jarvis deel is geworden van het denken van Stark.", philosophers: ["Clark"], kwestie: 3, vraagtype: "R+Arg" , lia: [{ deel: 2, hoofdstuk: 8, pagina: "2–6" }] },
  { year: "2025-T2", nr: 2, points: 4, opgave: "Superhelden en het wezen van de mens", context: "Volgens Clark verandert het wezen van de mens niet door de omgang met techniek, zelfs niet als die techniek bestaat uit dynamische apparaten. Het Iron Man-pak met Jarvis past zich aan Stark aan via AI.", question: "Geef Clarks beschrijving van het wezen van de mens weer. Leg vervolgens uit dat het Iron Man-pak met Jarvis een dynamisch apparaat is. Geef tot slot met het voorbeeld van Tony Stark/Iron Man: een argument voor Clarks opvatting dat het wezen van de mens niet verandert door de omgang met een dynamisch apparaat, en een argument tegen Clarks opvatting dat het wezen van de mens niet verandert door de omgang met een dynamisch apparaat.", model: "1p weergave wezen mens volgens Clark: natural born cyborgs / mensen zijn van nature kunstmatig / mens-technologiehybride. 1p uitleg dat Iron Man-pak met Jarvis dynamisch apparaat is: Jarvis leert om zich aan te passen aan informatie die Stark nodig heeft. 1p argument voor Clarks opvatting met voorbeeld Tony Stark/Iron Man. 1p argument tegen Clarks opvatting met voorbeeld Tony Stark/Iron Man.", philosophers: ["Clark"], kwestie: 3, vraagtype: "R+T+Arg" , lia: [{ deel: 2, hoofdstuk: 8, pagina: "2–6" }] },
  { year: "2025-T2", nr: 3, points: 3, opgave: "Superhelden en het wezen van de mens", context: "Iron Man/Tony Stark worstelt met zichzelf: hij heeft soms geen zin om met andere superhelden de wereld te redden en wil liever thuis technische foefjes uitvinden, maar er blijft iets knagen omdat hij weet dat wereldredden bij een superheld hoort. Het verschil tussen eerstepersoons- en derdepersoonsperspectief kan deze worsteling verhelderen.", question: "Geef weer wat beide perspectieven op de vraag naar de mens inhouden. Leg vervolgens met beide perspectieven de worsteling van Iron Man/Tony Stark met zichzelf uit.", model: "1p weergave eerstepersoonsperspectief: hoe jij je bestaan ervaart. 1p weergave derdepersoonsperspectief: een beschrijving van buitenaf van een set essentiële eigenschappen. 1p uitleg worsteling met beide perspectieven: Iron Man/Tony Stark ervaart verlangens/neigingen die tegengesteld zijn aan de essentiële eigenschap van superhelden om de wereld te redden.", philosophers: [], kwestie: 4, vraagtype: "R+T" , lia: [{ deel: 1, hoofdstuk: 1, pagina: "5–9" }] },
  { year: "2025-T2", nr: 4, points: 1, opgave: "Superhelden en het wezen van de mens", context: "Helmuth Plessner formuleert de wet van de utopische standplaats. Tony Stark/Iron Man ervaart als concreet individu begrenzing in zijn rol als superheld terwijl hij ook boven zichzelf wil uitstijgen.", question: "Leg met deze wet Iron Mans/Tony Starks worsteling met zichzelf uit.", model: "1p uitleg worsteling met wet van utopische standplaats: Tony Stark/Iron Man kan als mens/superheld boven zichzelf uitstijgen, maar ervaart als concreet individu/superheld altijd begrenzing / ontworteling.", philosophers: ["Plessner"], kwestie: 4, vraagtype: "T" , lia: [{ deel: 1, hoofdstuk: 3, pagina: "19–21" }] },
  { year: "2025-T2", nr: 5, points: 1, opgave: "Superhelden en het wezen van de mens", context: "Marvel-superheld Michael Morbius is een biochemicus met een zeldzame bloedziekte die in zijn lab experimenten doet met vampiervleermuizen en zo een medicijn creëert dat zijn DNA aanpast en hem geneest. Karen Barad stelt dat mensen een verstrengeling zijn van materiaal en betekenis.", question: "Leg met het voorbeeld van Morbius de opvatting van Barad uit dat mensen een verstrengeling zijn van materiaal en betekenis.", model: "1p uitleg Barad met Morbius: de verschillende elementen (Morbius als onderzoeker, zijn ziekte, de wens om te genezen, het lab/het medicijn, de vampiervleermuizen) ontstaan als fenomeen in de praktijk van het onderzoek.", philosophers: ["Barad"], kwestie: 4, vraagtype: "T" , lia: [{ deel: 2, hoofdstuk: 14, pagina: "40–41" }] },
  { year: "2025-T2", nr: 6, points: 2, opgave: "Superhelden en het wezen van de mens", context: "Door zijn DNA-aanpassing krijgt Morbius vampiereigenschappen: hij heeft bloed nodig en heeft een sterke neiging mensen aan te vallen. Hij geeft daar niet aan toe en steelt in plaats daarvan zakken bloed uit het lab, omdat hij zijn neiging niet kan verantwoorden.", question: "Leg uit dat Morbius zijn handelwijze om niet toe te geven aan zijn neiging, kan verantwoorden: vanuit de deugdethiek, en vanuit de plichtethiek.", model: "1p uitleg deugdethiek: Morbius handelt vanuit een deugd/karakterhouding als midden tussen twee extremen / hij neemt als gemeenschapswezen de deugd als uitgangspunt. 1p uitleg plichtethiek: hij handelt volgens een regel waarvan je redelijkerwijs kunt willen dat het een algemene wet is / hij beschouwt anderen niet louter als middel maar ook altijd als doel op zichzelf / hij gaat van principes/plicht uit ongeacht het resultaat.", philosophers: [], kwestie: 1, vraagtype: "T" , lia: [] },
  { year: "2025-T2", nr: 7, points: 3, opgave: "Superhelden en het wezen van de mens", context: "Volgens Jos de Muls speculatieve benadering kan de verandering van de mens zich voltrekken volgens drie verschillende scenario's. De fictieve superhelden Morbius (DNA-aanpassing) en Iron Man (neurotechnologie via Jarvis) zijn op te vatten als zulke scenario's.", question: "Leg uit van welk scenario van De Mul superheld Morbius een voorbeeld is. Leg vervolgens uit van welk scenario van De Mul superheld Iron Man een voorbeeld is. Beargumenteer tot slot welk van beide scenario's jij een verbetering van de mens vindt. Maak daarbij een afweging van de twee scenario's met de bijbehorende superhelden.", model: "1p uitleg Morbius als alienscenario/transhumanisme: biochemische transformatie van de menselijke levensvorm. 1p uitleg Iron Man als zwermgeestscenario/extrahumanisme: neurotechnologische verbetering van de menselijke cognitie. 1p argumentatie welk scenario een verbetering is, met afweging van beide scenario's met bijbehorende superhelden.", philosophers: ["De Mul"], kwestie: 4, vraagtype: "T+Arg" , lia: [{ deel: 2, hoofdstuk: 11, pagina: "19–23" }] },
  { year: "2025-T2", nr: 8, points: 2, opgave: "Het metaverse", context: "Journalist Joanna Stern brengt 24 uur door in virtuele omgevingen via een VR-bril. In het VR-café voelen diepte en perspectief eerst vreemd voor haar; om een virtueel drankje aan te pakken moet ze uitproberen hoe ver ze haar arm moet uitstrekken. Maxine Sheets-Johnstone gebruikt het begrip lichaamsschema in haar fenomenologische benadering van dans.", question: "Leg met het voorbeeld van het aanpakken van het virtuele drankje uit wat Sheets-Johnstone bedoelt met het lichaamsschema. Leg vervolgens uit in welk opzicht Sheets-Johnstones fenomenologische benadering geen betrekking heeft op het voorbeeld van het aanpakken van het virtuele drankje.", model: "1p uitleg lichaamsschema met virtueel drankje: de geleefde ervaring van de ruimtelijkheid van je lichaam in de wereld, die in een virtuele omgeving anders is dan in een fysieke omgeving. 1p uitleg waarom fenomenologische benadering geen betrekking heeft: fenomenologie wil de pre-reflectieve gewaarwording van het bewegende lichaam onderzoeken, terwijl Stern bewust moet nadenken over hoe ze het virtuele drankje moet aanpakken.", philosophers: ["Sheets-Johnstone"], kwestie: 3, vraagtype: "T" , lia: [{ deel: 1, hoofdstuk: 2, pagina: "12–15" }] },
  { year: "2025-T2", nr: 9, points: 2, opgave: "Het metaverse", context: "Na een tijdje vergeet Stern dat ze in een VR-café is en geniet ze van het praten met onbekenden. Andy Clark beschrijft twee manieren van omgaan met techniek met de begrippen interface en cyborg.", question: "Geef met de begrippen interface en cyborg het verschil weer tussen deze twee manieren van omgaan met techniek. Ga daarbij in op de ervaringen van Stern in het VR-café.", model: "1p weergave verschil interface/cyborg: volgens Clark kan het nodig zijn om aandacht bewust op de techniek te richten (interface) of kan dit naar de achtergrond van ons handelen verdwijnen (cyborg). 1p toepassing op Stern: eerst moet Stern haar aandacht richten op de VR-techniek om te ontdekken hoe die werkt, terwijl ze later vergeet dat ze de VR-techniek gebruikt.", philosophers: ["Clark"], kwestie: 3, vraagtype: "V" , lia: [{ deel: 2, hoofdstuk: 8, pagina: "2–6" }] },
  { year: "2025-T2", nr: 10, points: 2, opgave: "Het metaverse", context: "Als Stern de VR-bril afdoet, heeft ze hoofdpijn en zere ogen, maar realiseert ze zich ook dat ze zich in het VR-café - verscholen achter haar avatar - anoniemer en vrijer voelde dan in de fysieke wereld. Petran Kockelkoren beschrijft de processen van decentreren en recentreren.", question: "Leg uit dat in Sterns ervaring met VR de processen van decentreren en recentreren zijn te herkennen.", model: "1p uitleg decentreren: door de VR-bril raakt Stern zintuiglijk gedesoriënteerd / krijgt ze een ander zicht op de omgeving. 1p uitleg recentreren: de (ingelijfde) VR-techniek transformeert Sterns ervaring van zichzelf in de wereld.", philosophers: ["Kockelkoren"], kwestie: 3, vraagtype: "T" , lia: [{ deel: 2, hoofdstuk: 9, pagina: "7–12" }] },
  { year: "2025-T2", nr: 11, points: 2, opgave: "Het metaverse", context: "In het metaverse spelen data een grote rol. Yuval Noah Harari beschrijft de ontwikkeling van techno-humanisme naar dataïsme. Volgens Miriam Rasch moeten we ons verzetten tegen het dataïsme met haar begrip 'het else'.", question: "Leg de ontwikkeling van techno-humanisme naar dataïsme uit. Leg vervolgens uit dat het begrip het else volgens Rasch een mogelijkheid biedt voor verzet tegen dataïsme.", model: "1p uitleg ontwikkeling: het techno-humanisme stelt de verlangens van de mens centraal, terwijl in het dataïsme alleen data nog waarde hebben. 1p uitleg het else als verzet: het else benoemt het vreemde/andere/spontane dat niet in data is uit te drukken / benoemt ons vermogen om ons tot onze data te verhouden, waardoor wij ons kunnen verzetten tegen de opvatting dat alles data is.", philosophers: ["Harari", "Rasch"], kwestie: 4, vraagtype: "T" , lia: [{ deel: 2, hoofdstuk: 14, pagina: "41–42" }, { deel: 2, hoofdstuk: 14, pagina: "42–43" }] },
  { year: "2025-T2", nr: 12, points: 1, opgave: "Het metaverse", context: "Virtuele omgevingen worden in toenemende mate gecreëerd door AI op basis van bestaande databases. Niet-inclusieve eigenschappen kunnen eindeloos worden herhaald: avatars met kroeshaar leken steil haar te hebben en VR is slecht toegankelijk voor blinden. Katherine Hayles wijst op ethische gevolgen van niet-bewuste cognitie.", question: "Leg uit dat niet-bewuste cognitie volgens Hayles geen morele verantwoordelijkheid zal kunnen nemen. Ga daarbij in op het creëren van inclusieve omgevingen.", model: "1p uitleg geen morele verantwoordelijkheid met inclusieve omgevingen: niet-bewuste cognitie is niet kwetsbaar / heeft geen emotie / heeft geen omvattende wereldhorizon / heeft geen empathische vermogens om anderen te begrijpen, waardoor deze niet in staat is verantwoordelijkheid te nemen voor inclusieve omgevingen.", philosophers: ["Hayles"], kwestie: 2, vraagtype: "T" , lia: [{ deel: 2, hoofdstuk: 13, pagina: "36–37" }] },
  { year: "2025-T2", nr: 13, points: 2, opgave: "Het metaverse", context: "Een VR-training laat mensen ervaren hoe het is om gediscrimineerd te worden: VR-personages negeren je bijdragen en gaan uit van vooroordelen. De VR-wereld is op te vatten als medewereld. Plessner heeft invulling gegeven aan dit begrip; existentialisten als De Beauvoir en Fanon geven een iets andere invulling.", question: "Leg het verschil uit tussen Plessners invulling van het begrip medewereld en die van de existentialisten. Leg uit bij welke van deze twee invullingen van het begrip medewereld de VR-training het best aansluit.", model: "1p uitleg verschil: Plessner benadrukt onze expressiviteit tegenover de medemens, existentialisten benadrukken dat wij door de wereld van de medemensen worden gevormd. 1p uitleg dat VR-training best aansluit bij existentialisten: omdat gepoogd wordt de deelnemers te laten ervaren dat hun bestaanservaring mede wordt gevormd door medemensen.", philosophers: ["Plessner", "De Beauvoir", "Fanon"], kwestie: 4, vraagtype: "V" , lia: [{ deel: 1, hoofdstuk: 3, pagina: "19–21" }, { deel: 1, hoofdstuk: 4, pagina: "25–26" }, { deel: 1, hoofdstuk: 4, pagina: "26–27" }] },
  { year: "2025-T2", nr: 14, points: 2, opgave: "Het metaverse", context: "Fanon beschrijft zijn ervaringen met racisme. In de VR-training tegen discriminatie worden deelnemers genegeerd en aan vooroordelen onderworpen, maar kunnen ze de bril daarna afdoen.", question: "Beargumenteer of jij de VR-training een goede manier vindt om inclusie te bevorderen, met: een uitleg van de overeenkomst tussen Fanons bestaanservaring en de situatie van een deelnemer aan de VR-training, en een uitleg van het verschil tussen Fanons bestaanservaring en de situatie van een deelnemer aan de VR-training.", model: "1p uitleg overeenkomst: zowel Fanon als de deelnemer aan de VR-training wordt tot object gemaakt. 1p uitleg verschil: de bestaanservaring van Fanon, in tegenstelling tot die van de deelnemer aan de VR-training, wordt door de objectivering vertroebeld/overstemd. Opmerking: als overeenkomst en verschil juist worden uitgelegd zonder in (juiste) argumentatie opgenomen, kan voor uitleg samen 1 scorepunt worden toegekend.", philosophers: ["Fanon"], kwestie: 4, vraagtype: "Arg" , lia: [{ deel: 1, hoofdstuk: 4, pagina: "26–27" }] },
  { year: "2025-T2", nr: 15, points: 2, opgave: "Het metaverse", context: "Toekomstvisies beschrijven een chip in het brein die zintuiglijke ervaringen via breinsignalen opwekt, zoals een VR-vakantie waarin je in een jungle rondloopt vanuit het perspectief van een vis of vogel. Dick Swaab stelt dat wij ons brein zijn. Belichaamd denken (embodied cognition) is een stroming binnen 4E.", question: "Beargumenteer of jij het met Swaab eens bent dat wij ons brein zijn, met: het voorbeeld van VR via breinsignalen, en de 4E-stroming belichaamd denken.", model: "1p argumentatie of Swaab gelijk heeft dat wij ons brein zijn omdat onze hersenen al onze ervaringen veroorzaken, met voorbeeld VR via breinsignalen. 1p argumentatie met de 4E-stroming belichaamd denken, die stelt dat kennis een basis heeft in onze lichamelijke verhouding tot de omgeving.", philosophers: ["Swaab"], kwestie: 2, vraagtype: "Arg" , lia: [{ deel: 1, hoofdstuk: 6, pagina: "36–37" }] },
  { year: "2025-T2", nr: 16, points: 3, opgave: "Het metaverse", context: "Toekomstvisies over computerchips in het brein versterken de computermetafoor voor de mens. De computermetafoor was oorspronkelijk gebaseerd op traditionele computers met symboolmanipulatie; later kwamen neurale netwerken. Volgens Vroon en Draaisma zijn machinemetaforen historisch contingent.", question: "Leg de computermetafoor uit met het begrip symboolmanipulatie. Beargumenteer vervolgens of de computermetafoor volgens jou helpt om de mens te begrijpen. Ga daarbij in op: neurale netwerken, en Vroon & Draaisma's stelling dat machinemetaforen historisch contingent zijn.", model: "1p uitleg computermetafoor met symboolmanipulatie: het menselijk brein werkt net als een computer door middel van de omzetting van input (prikkels) in output (gedrag), via een reeks instructies. 1p argumentatie waarbij wordt ingegaan op neurale netwerken die net als de mens zelflerend zijn / patronen kunnen herkennen. 1p argumentatie waarbij wordt ingegaan op Vroon & Draaisma's stelling dat machinemetaforen onder invloed van cultuur door de tijd heen veranderen.", philosophers: ["Vroon", "Draaisma"], kwestie: 2, vraagtype: "T+Arg" , lia: [{ deel: 1, hoofdstuk: 5, pagina: "32–33" }] },
  { year: "2025-T2", nr: 17, points: 4, opgave: "Oog in oog met een beer", context: "Antropoloog Natasja Martin onderzoekt animisme: er is geen scheidslijn tussen natuur en cultuur, mens en niet-mens; alles deelt een universele ziel. Donna Haraway bekritiseert dualistisch denken eveneens, maar gebruikt het beeld van de mens als cyborg in plaats van een universele ziel.", question: "Geef weer waarom Haraway het beeld van de mens als cyborg gebruikt. Beargumenteer vervolgens welke opvatting over de mens jij het meest overtuigend vindt, die van Haraway of die van het animisme. Geef in je argumentatie: een afweging van de opvattingen van Haraway en het animisme, een uitleg van het begrip monisme, en een uitleg van het begrip dualisme.", model: "1p weergave Haraway's cyborg: grenzen moeten vervagen, omdat de mens geen vastomlijnde identiteit heeft / omdat dit uitsluiting tegengaat. 1p afweging Haraways cyborg vs. animistische opvatting van mens als wezen met ziel/geest verbonden met universele ziel. 1p uitleg monisme: er is één substantie. 1p uitleg dualisme: er zijn twee substanties.", philosophers: ["Haraway"], kwestie: 4, vraagtype: "R+Arg" , lia: [{ deel: 2, hoofdstuk: 12, pagina: "26" }, { deel: 2, hoofdstuk: 14, pagina: "46–47" }] },
  { year: "2025-T2", nr: 18, points: 2, opgave: "Oog in oog met een beer", context: "Tekst 1 (Martin, Geloven in het wild, 2022): \"Mijn lichaam na de beer na zijn klauwen, mijn lichaam in het bloed en zonder de dood, mijn lichaam vol leven, draden en handen, mijn lichaam in de vorm van een open wereld waar meervoudige wezens elkaar ontmoeten, mijn lichaam dat zich met hen herstelt, zonder hen [...].\" Plessner beschrijft excentrische positionaliteit en de wet van natuurlijke kunstmatigheid.", question: "Leg uit wat Plessner bedoelt met excentrische positionaliteit, met: tekst 1, en de wet van natuurlijke kunstmatigheid.", model: "1p uitleg met tekst 1: Martin kan zich verhouden tot haar eigen bestaan, waarin ze zich verbonden voelt met andere wezens. 1p uitleg met wet van natuurlijke kunstmatigheid: de mens is geplaatst tegenover zijn bestaan en moet zijn bestaan ten uitvoer brengen vanuit een bestaanservaring die hem van nature gegeven is.", philosophers: ["Plessner"], kwestie: 4, vraagtype: "T" , lia: [{ deel: 1, hoofdstuk: 3, pagina: "19–21" }] },
  { year: "2025-T2", nr: 19, points: 1, opgave: "Oog in oog met een beer", context: "In Geloven in het wild probeert Martin vanuit allerlei invalshoeken te achterhalen wat de confrontatie met de beer voor haar betekend heeft. Haar boek is een onderzoek naar de verhouding tussen mens en dier en een literair verslag van haar transformatie.", question: "Leg de wet van de bemiddelde onmiddellijkheid uit met het voorbeeld van Martins boek.", model: "1p uitleg wet van bemiddelde onmiddellijkheid met Martins boek: in haar boek drukt Martin haar onmiddellijke ervaring uit en haar bemiddelde ervaring tussen zichzelf en de omgeving.", philosophers: ["Plessner"], kwestie: 4, vraagtype: "T" , lia: [{ deel: 1, hoofdstuk: 3, pagina: "19–21" }] },
  { year: "2025-T2", nr: 20, points: 2, opgave: "Oog in oog met een beer", context: "Tekst 1 beschrijft Martins lichaam als open wereld waar meervoudige wezens elkaar ontmoeten. Tekst 2 (Martin, 2022): \"Het houvast breekt af, de rotsen vallen, zo staat het ervoor. En de vrienden storten te pletter aan de voet van de rotswand. ... ik heb één zekerheid: er resoneert iets in mij, iets wat pijn doet en desoriënteert.\" Beide teksten vertonen overeenkomsten met aspecten van Mortons ecologisch denken.", question: "Leg uit welk aspect van Mortons ecologische denken te herkennen is in tekst 1. Leg vervolgens uit welk ander aspect van Mortons ecologische denken te herkennen is in tekst 2.", model: "1p uitleg tekst 1: onderlinge verbondenheid als aspect van Mortons ecologisch denken. 1p uitleg tekst 2: desoriënterende openheid als aspect van Mortons ecologisch denken.", philosophers: ["Morton"], kwestie: 1, vraagtype: "T" , lia: [{ deel: 2, hoofdstuk: 12, pagina: "24–27" }] },
  { year: "2025-T2", nr: 21, points: 2, opgave: "Oog in oog met een beer", context: "Dierenactivist Timothy Treadwell verbleef 13 zomers tussen grizzlyberen in Alaska, kwam erg dichtbij, raakte hen aan en speelde met jonge beren; door deze relatie zei hij een uitweg uit zijn verslaving te vinden. Vinciane Despret pleit voor andere benadering van dierenonderzoek met twee uitgangspunten: het eerste is dat onderzoekers ook het perspectief van het dier moeten betrekken.", question: "Geef het andere uitgangspunt weer waar Despret voor pleit in wetenschappelijk onderzoek naar het gedrag van dieren. Beargumenteer vervolgens met het voorbeeld van Treadwell of je het met dit uitgangspunt van Despret eens bent.", model: "1p weergave ander uitgangspunt: volgens Despret moet de relatie tussen dier en onderzoeker een actieve rol spelen in het wetenschappelijk onderzoek naar het gedrag van dieren. 1p argumentatie met voorbeeld van Treadwell of de relatie tussen dier en onderzoeker een actieve rol moet spelen in het onderzoek.", philosophers: ["Despret"], kwestie: 1, vraagtype: "R+Arg" , lia: [{ deel: 2, hoofdstuk: 12, pagina: "28–30" }] },
];